import * as React from 'react';
import Box from '@mui/material/Box';

function About () {
	return (
		<Box
      sx={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
				backgroundColor: 'grey'
      }}
    >
			<Typography component="h1"
        sx={{
          fontSize: '28px',
          marginBottom: '0px',
          fontWeight: '300',
        }}
      >
        About Me
      </Typography>
		</Box>
	)
}

export default About;
